example.query:
-- 1. Basic join
SELECT s.name, e.course FROM Students AS s INNER JOIN Enrollments AS e ON s.id = e.student_id;

-- 2. Join with a filter
SELECT s.name, e.course FROM Students AS s INNER JOIN Enrollments AS e ON s.id = e.student_id WHERE s.marks > 70;

shared_table.create_sql:
CREATE TABLE Enrollments (
  id INTEGER PRIMARY KEY,
  student_id INTEGER,
  course TEXT
);
